import React, { createContext, useContext } from 'react';
import { useParams } from 'react-router-dom';

export type FormEmbedMode = 'page' | 'slideout';

type FormEmbedContextValue = {
  mode: FormEmbedMode;
  documentId?: string;
};

const defaultValue: FormEmbedContextValue = { mode: 'page' };

const FormEmbedContext = createContext<FormEmbedContextValue>(defaultValue);

export type FormEmbedProviderProps = {
  mode: FormEmbedMode;
  /** Slide-out embed: document id (avoids nested MemoryRouter). */
  documentId?: string;
  children: React.ReactNode;
};

export const FormEmbedProvider: React.FC<FormEmbedProviderProps> = ({
  mode,
  documentId,
  children,
}) => (
  <FormEmbedContext.Provider value={{ mode, documentId }}>{children}</FormEmbedContext.Provider>
);

export function useFormEmbedMode(): FormEmbedMode {
  return useContext(FormEmbedContext).mode;
}

/** True when voucher form is embedded in report slide-out (display-only, no toolbar). */
export function useFormEmbedSlideout(): boolean {
  return useFormEmbedMode() === 'slideout';
}

/** Route `:id` — uses embed documentId in slide-out, else `useParams`. */
export function useFormRouteId(): string | undefined {
  const embed = useContext(FormEmbedContext);
  const { id } = useParams<{ id: string }>();
  if (embed.mode === 'slideout' && embed.documentId) {
    return embed.documentId;
  }
  return id;
}
